const category = $('Loop Over Feeds').first().json.category;
const items = $input.all();
return items.map(item => {
  item.json._category = category;
  return item;
});

const staticData = $getWorkflowStaticData('global');
if (!staticData.seenUrls) staticData.seenUrls = {};

const now = Date.now();
const twentyFourHoursAgo = now - (24 * 60 * 60 * 1000);
const sevenDaysAgo = now - (7 * 24 * 60 * 60 * 1000);

for (const [url, ts] of Object.entries(staticData.seenUrls)) {
  if (ts < sevenDaysAgo) delete staticData.seenUrls[url];
}

const results = [];
for (const item of $input.all()) {
  const a = item.json;
  if (!a.link && !a.url) continue;
  const link = (a.link || a.url || '').split('?')[0].replace(/\/+$/, '').toLowerCase();
  if (!link) continue;
  if (staticData.seenUrls[link]) continue;
  const pubDate = new Date(a.isoDate || a.pubDate || a.date || 0).getTime();
  if (pubDate < twentyFourHoursAgo && pubDate > 0) continue;
  staticData.seenUrls[link] = now;
  const source = link.split('/')[2].replace('www.', '').replace('blog.', '').replace('feeds.', '');
  let snippet = a.contentSnippet || a.content || a.description || '';
  snippet = snippet.replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
  if (snippet.length > 300) snippet = snippet.substring(0, 300) + '...';
  results.push({
    json: {
      title: a.title || 'Sans titre',
      url: a.link || a.url,
      source: source,
      category: a._category || 'tendances',
      snippet: snippet,
      publishedAt: a.isoDate || a.pubDate || a.date || new Date().toISOString()
    }
  });
}

if (results.length === 0) {
  return [{ json: { _empty: true, count: 0 } }];
}
return results;

