const MAX_PER_CATEGORY = 10;
const TOTAL_LIMIT = 50;

const items = $input.all();
const scored = [];

for (const item of items) {
  const text = ((item.json.title || '') + ' ' + (item.json.snippet || '')).toLowerCase();
  let bestScore = 0;
  let bestCategory = item.json.category || 'tendances';

  for (const [cat, words] of Object.entries(KEYWORDS)) {
    let score = 0;
    for (const w of words.high) { if (text.includes(w)) score += 3; }
    for (const w of words.medium) { if (text.includes(w)) score += 2; }
    for (const w of words.low) { if (text.includes(w)) score += 1; }
    if (score > bestScore) {
      bestScore = score;
      bestCategory = cat;
    }
  }

  if (bestScore < 3) bestCategory = item.json.category || 'tendances';

  const score10 = Math.min(10, Math.max(1, Math.round(bestScore / 3) + 3));
  let priority = 'VEILLE';
  if (score10 >= 9) priority = 'CRITIQUE';
  else if (score10 >= 7) priority = 'IMPORTANT';
  else if (score10 < 5) priority = 'BRUIT';

  scored.push({
    json: {
      title: item.json.title,
      url: item.json.url,
      source: item.json.source,
      snippet: item.json.snippet,
      publishedAt: item.json.publishedAt,
      score: score10,
      priority: priority,
      category: bestCategory,
      summary: item.json.snippet || '',
      keywordScore: bestScore
    }
  });
}

scored.sort((a, b) => b.json.keywordScore - a.json.keywordScore);

// Quota par categorie : max 10 par cat, 50 total
const catCount = {};
const selected = [];
for (const item of scored) {
  const cat = item.json.category;
  catCount[cat] = (catCount[cat] || 0) + 1;
  if (catCount[cat] <= MAX_PER_CATEGORY) {
    selected.push(item);
  }
  if (selected.length >= TOTAL_LIMIT) break;
}

// Si pas assez, completer avec les meilleurs restants
if (selected.length < TOTAL_LIMIT) {
  const selectedUrls = new Set(selected.map(i => i.json.url));
  for (const item of scored) {
    if (!selectedUrls.has(item.json.url)) {
      selected.push(item);
      if (selected.length >= TOTAL_LIMIT) break;
    }
  }
}

return selected;

const items = $input.all();
const articles = items.map((item, i) => {
  const a = item.json;
  const content = a.fullText || a.snippet || 'N/A';
  return `[${i+1}] Titre: ${a.title}\nSource: ${a.source}\nCategorie RSS: ${a.category}\nContenu: ${content}`;
}).join('\n\n');

const prompt = `Tu es un analyste tech senior. Classifie ces ${items.length} articles.

Pour CHAQUE article, reponds en JSON avec:
- title: le titre original
- url: garder l'URL originale
- score: pertinence de 1 a 10 (10 = revolution majeure, 7-8 = important, 5-6 = interessant, 1-4 = bruit)
- priority: CRITIQUE (9-10), IMPORTANT (7-8), VEILLE (5-6), BRUIT (1-4)
- category: une parmi [ia-ml, data-eng, cloud, devops, securite, tendances]
- summary: resume en 1 phrase francaise, factuel, sans jargon marketing

ARTICLES:
${articles}

URLS ORIGINALES:
${items.map((item, i) => `[${i+1}] ${item.json.url}`).join('\n')}

Reponds UNIQUEMENT avec un JSON valide: {"articles": [...]}`;

return [{ json: { prompt, _batchItems: items.map(i => i.json) } }];

const input = $input.first().json;
const text = input.text || input.output || '';
const batchItems = input._batchItems || $('Format Prompt LLM').first().json._batchItems || [];

try {
  let jsonStr = text;
  const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) jsonStr = jsonMatch[1];

  const objMatch = jsonStr.match(/\{[\s\S]*\}/);
  if (objMatch) jsonStr = objMatch[0];

  const parsed = JSON.parse(jsonStr);
  const articles = parsed.articles || parsed;

  if (!Array.isArray(articles)) {
    throw new Error('articles is not an array');
  }

  return articles.map((a, i) => {
    const original = batchItems[i] || {};
    return {
      json: {
        title: a.title || original.title || 'Sans titre',
        url: a.url || original.url || '',
        source: original.source || '',
        score: Math.min(10, Math.max(1, parseInt(a.score) || 5)),
        priority: ['CRITIQUE', 'IMPORTANT', 'VEILLE', 'BRUIT'].includes(a.priority) ? a.priority : 'VEILLE',
        category: a.category || original.category || 'tendances',
        summary: a.summary || original.snippet || '',
        publishedAt: original.publishedAt || new Date().toISOString()
      }
    };
  });
} catch (e) {
  return batchItems.map(item => ({
    json: {
      title: item.title || 'Sans titre',
      url: item.url || '',
      source: item.source || '',
      score: item.score || 5,
      priority: item.priority || 'VEILLE',
      category: item.category || 'tendances',
      summary: item.snippet || '',
      publishedAt: item.publishedAt || new Date().toISOString(),
      _fallback: true
    }
  }));
}

const PRIORITY_COLORS = {
  'CRITIQUE': 15548997,
  'IMPORTANT': 16705372,
  'VEILLE': 5793266
};

const CATEGORY_EMOJI = {
  'ia-ml': '🤖',
  'data-eng': '📊',
  'cloud': '☁️',
  'devops': '⚙️',
  'securite': '🔒',
  'tendances': '📰'
};

const CHANNEL_MAP = {
  'ia-ml': 'IA',
  'data-eng': 'DEV',
  'cloud': 'CLOUD',
  'devops': 'DEV',
  'securite': 'SECURITE',
  'tendances': 'TENDANCES'
};

const items = $input.all();

const groups = {};
for (const item of items) {
  const cat = item.json.category || 'tendances';
  if (!groups[cat]) groups[cat] = [];
  groups[cat].push(item.json);
}

const messages = [];

for (const [cat, articles] of Object.entries(groups)) {
  articles.sort((a, b) => b.score - a.score);

  const channelKey = CHANNEL_MAP[cat] || 'TENDANCES';
  const emoji = CATEGORY_EMOJI[cat] || '📰';

  const topArticles = articles.slice(0, 5);
  const restArticles = articles.slice(5);

  const embeds = topArticles.map(a => {
    const color = PRIORITY_COLORS[a.priority] || 5793266;
    let desc = a.summary || '';
    if (desc.length > 300) desc = desc.substring(0, 300) + '...';

    return {
      title: `[${a.priority}] ${a.title}`.substring(0, 256),
      url: a.url,
      description: desc,
      color: color,
      fields: [
        { name: 'Score', value: `${a.score}/10`, inline: true },
        { name: 'Source', value: a.source || 'N/A', inline: true },
        { name: 'Categorie', value: cat, inline: true }
      ],
      footer: { text: 'Veille Pro' },
      timestamp: a.publishedAt || new Date().toISOString()
    };
  });

  if (restArticles.length > 0) {
    const list = restArticles.slice(0, 10).map(a => 
      `• [${a.title}](${a.url}) (${a.score}/10)`
    ).join('\n');
    const extra = restArticles.length > 10 ? `\n_...et ${restArticles.length - 10} autres_` : '';

    embeds.push({
      title: `${emoji} +${restArticles.length} autres articles`,
      description: list + extra,
      color: 5793266
    });
  }

  let currentEmbeds = [];
  let currentChars = 0;

  for (const embed of embeds) {
    const embedChars = (embed.title || '').length + (embed.description || '').length + 
      (embed.fields || []).reduce((s, f) => s + f.name.length + f.value.length, 0);

    if (currentEmbeds.length >= 10 || (currentChars + embedChars > 5500 && currentEmbeds.length > 0)) {
      messages.push({ json: { channelKey, content: '', embeds: currentEmbeds } });
      currentEmbeds = [];
      currentChars = 0;
    }
    currentEmbeds.push(embed);
    currentChars += embedChars;
  }

  if (currentEmbeds.length > 0) {
    messages.push({ json: { channelKey, content: '', embeds: currentEmbeds } });
  }
}

const critiques = items.filter(i => i.json.priority === 'CRITIQUE').map(i => i.json);
if (critiques.length > 0) {
  const critiqueEmbeds = critiques.slice(0, 5).map(a => ({
    title: `🚨 ${a.title}`.substring(0, 256),
    url: a.url,
    description: a.summary || '',
    color: 15548997,
    fields: [
      { name: 'Score', value: `${a.score}/10`, inline: true },
      { name: 'Source', value: a.source || 'N/A', inline: true },
      { name: 'Categorie', value: a.category, inline: true }
    ],
    footer: { text: 'ALERTE CRITIQUE' },
    timestamp: a.publishedAt || new Date().toISOString()
  }));
  messages.push({ json: { channelKey: 'CRITIQUE', content: '@here Alertes critiques detectees', embeds: critiqueEmbeds } });
}

if (messages.length === 0) {
  return [{ json: { channelKey: 'STATUS', content: 'Aucun article a distribuer', embeds: [] } }];
}

return messages;

const allItems = $('Filter Score >= 5').all();
const count = allItems.length;
const categories = {};
const priorities = {};

for (const item of allItems) {
  const cat = item.json.category || 'unknown';
  const pri = item.json.priority || 'unknown';
  categories[cat] = (categories[cat] || 0) + 1;
  priorities[pri] = (priorities[pri] || 0) + 1;
}

const catBreakdown = Object.entries(categories).map(([k, v]) => `${k}: ${v}`).join(', ');
const priBreakdown = Object.entries(priorities).map(([k, v]) => `${k}: ${v}`).join(', ');
const now = new Date();
const timeStr = now.toISOString().split('T')[0] + ' ' + now.toISOString().split('T')[1].split('.')[0];

return [{
  json: {
    content: `**Veille Pro terminee** \u2014 ${timeStr}\n\n\ud83d\udcca **${count} articles** distribues\n\ud83d\udcc2 Par categorie: ${catBreakdown}\n\ud83c\udfaf Par priorite: ${priBreakdown}`
  }
}];

const allItems = $('Filter Score >= 5').all();
const today = new Date().toISOString().split('T')[0];

const articles = allItems.map(i => i.json);
articles.sort((a, b) => (b.score || 0) - (a.score || 0));

const articleList = articles.slice(0, 30).map((a, i) => 
