const items = $input.all();
const results = [];

for (const item of items) {
  let fullText = '';
  try {
    const resp = await fetch('https://r.jina.ai/' + item.json.url, {
      headers: { 'Accept': 'text/plain' },
      signal: AbortSignal.timeout(10000)
    });
    if (resp.ok) {
      const text = await resp.text();
      fullText = text.substring(0, 1500);
    }
  } catch (e) {
    // fetch not available or failed - fallback to snippet
    fullText = '';
  }

  results.push({
    json: {
      ...item.json,
      fullText: fullText || item.json.snippet || item.json.title
    }
  });

  // Rate limit 300ms
  await new Promise(r => setTimeout(r, 300));
}

return results;

